query:
SELECT MONTH(createdAt) as mes, YEAR(createdAt) as ano, COUNT(*) as contratos, SUM(valorVenda) as vgv
FROM contratos WHERE distrato = 0 AND createdAt >= '2026-01-01'
GROUP BY YEAR(createdAt), MONTH(createdAt) ORDER BY ano DESC, mes DESC;

SELECT u.name, u.email, u.status, u.role FROM users u WHERE u.role IN ('gerente') ORDER BY u.name;

